var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"지금 보고 계신 것은 그로니아의 수도, 타나베린의 전경입니다.","JPN":"ただいまご覧になっているのはグロニアの首都、タナベリンの全景です。","ENG":"What you’re looking at is a panoramic view of Tanaberin, the capital of Gronia.","TWN":"現在各位觀眾所看到的，就是格羅尼亞的首都 達那貝林的全景。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"20년만의 건국절 기념식을 앞두고 건국기념전당 앞은 교통 통제 상태라는데요.","JPN":"20年ぶりの建国記念式を控えて、建国記念館前は交通規制されている状態です。","ENG":"Ahead of the 20th year anniversary celebration of National Foundation Day, traffic control has been deployed in front of the National Foundation Hall.","TWN":"在這裡，即將舉行睽違20年的國慶典禮，因此建國紀念堂前面目前是有交通管制的。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"아, 저 건물. 유명했죠. 당시엔 재정 파탄의 원흉이란 비난을 받았습니다만.","JPN":"あ、あの建物。有名でしたね。当時には財政破綻の元凶と責められましたが。","ENG":"Ah, that’s a pretty famous building, right? It was related to a massive economic collapse.","TWN":"喔～那個建築物很有名呢！雖然當時被大家指責是財政破口的原因。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"반정부주의 단체들이 내세웠던 가장 큰 명분이기도 하고요.","JPN":"反政府主義団体が掲げた最大の名分でもありますしね。","ENG":"That was one of the biggest arguments put forth by the anti-government troops.","TWN":"這也是最為反政府勢力所詬病的。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"그런데 내전은 아직 현재진행형 아닙니까? 왜 그로니아는 기념식을 강행하려는 걸까요?","JPN":"ところで内戦はまだ終結してないですよね？　なぜグロニアは記念式を強行するのでしょうか？","ENG":"But isn’t the civil war still ongoing? Why would Gronia want to continue with the ceremony?","TWN":"不過內戰不是現在進行式嗎？為什麼格羅尼亞非要在這個時候舉行典禮呢？"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"순혈지식 연대의 거점이 공격 받은 뒤로는 반군들이 예전 같지 않죠. 가장 강성했던 세력이었으니까요.","JPN":"純血知識連帯の拠点が攻撃された後から、反乱軍も本調子ではありません。あそこがもっとも強い勢力でしたからね。","ENG":"The rebel forces haven’t been the same ever since the Pureblood Knowledge Regiment’s main base was attacked. It was the hardliner rebels’ largest force.","TWN":"純血知識年代的據點受到攻擊後，叛軍的氣勢就大不如前，畢竟他們是最強盛的勢力。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"거점 위치가 유출된 데 대한 책임 소재로 강경파와 온건파의 대립이 심화되었고…….","JPN":"拠点の位置が流出したことに対する責任の所在で、強硬派と穏健派の対立が深まり……","ENG":"Determining who was at fault for leaking the secret location of the base has intensified the conflict between the hardliners and the moderates.","TWN":"據點位置曝光的責任歸屬問題，也加深強硬派和溫和派的對立……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"강경파가 기상 조절기를 밀매했다는 사실이 드러나 외부 지원도 끊긴 모양입니다.","JPN":"強硬派が気象調節器を密売したという事実が明らかになって外部からの支援も途絶えたようです。","ENG":"External support has begun to wane after the hardliners were found to have illegally trafficked the weather controller.","TWN":"強硬派走私氣象調節器的事情曝光後，外界的支援似乎也已經中斷。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"악용하기에 따라서는 침식 현상만큼 무서운 재난을 불러올 수 있을 테니까요.","JPN":"悪用されたら侵食現象ぐらいの恐ろしい厄災を招くでしょうからね。","ENG":"With potential misuse, it could lead to a massive environmental disaster as dangerous as the Counterside Effect.","TWN":"畢竟萬一遭到有心人士的濫用，很可能會造成像是侵蝕現象那樣可怕的災難。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"본론으로 돌아가서, 그로니아의 건국절 하면 역시 건국기념전당에서 열리는 음악회죠?","JPN":"本題に戻りまして、グロニアの建国記念日といえばやはり建国記念館で開かれる音楽会が欠かせないですよね？","ENG":"Returning to the topic at hand, the highlight of Gronia’s National Foundation Day is a concert held at the National Foundation Hall, correct?","TWN":"回到今天的主題，提到格羅尼亞的國慶典禮，就不能不提到在建國紀念堂的音樂會吧？"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"그럼요. 내전이 있기 전에는 음악가라면 누구나 평생에 한 번쯤 서고 싶은 자리였죠.","JPN":"ええ。内戦が起こる前は、音楽家であれば一生に一度は立ってみたいという場でした。","ENG":"That’s right. Before the civil war, it was every musician’s dream to one day be able to perform there.","TWN":"那是當然的！在內戰爆發之前，那可是每一個音樂家一生中所追求的最高殿堂呢！"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"대표적으로 과거 망명했던 클림트 씨가…….","JPN":"代表としては過去、亡命したクリムト氏が……","ENG":"Representative musician is Mr. Klimt who had fled the country in the past...","TWN":"最具代表性的就是先前流亡海外的克里姆……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"참 한가한 소리죠? 누군 전쟁터에서 구르다 병원 신세를 지는데 축제를 연다네요.","JPN":"のんきだよね？　こっちは戦場で怪我して病院送りになってるのに、お祭りだなんて。","ENG":"Ahhh. Isn’t this wonderful? Someone’s here rolling an ankle one day on the battlefield, and there’s a festival going on.","TWN":"真是吃飽沒事幹，有人在戰場上拼命結果被送進醫院，有人卻要舉辦國慶典禮？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"물론 전 평범한 꾀병이었지만요.","JPN":"もちろん私はただの仮病だけど。","ENG":"Of course, I completely faked my injury, you know.","TWN":"雖然我是裝病的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐가 아쉽다고 죽을 둥 살 둥 싸워요? 등신도 아니고.","JPN":"何のために死ぬ気で戦うの？　バカじゃあるまいし。","ENG":"What’s wrong with that? You expect me to fight tooth and nail to the end? I’m not an idiot.","TWN":"我還有那麼美好的人生，才不想浪費生命在戰爭上呢！我才沒那麼傻咧！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"효율적으로. 적당적당히. 이 나라에서 생존하려면 모난 구석 없게 살아야 돼요.","JPN":"効率的に。適当に。この国で生きていくには丸く生きないとダメなんだよ。","ENG":"The way to survive in this country is to be efficient and practical.","TWN":"要想安穩地在這個國家生存，還是必須狡猾一點。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};